bool solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n < 3) return false;

    int p = 1, q = 2;

    // Find p such that nums[0...p] is strictly increasing
    while (p < n - 1 && nums[p] > nums[p - 1]) {
        p++;
    }

    // Find q such that nums[p...q] is strictly decreasing
    while (q < n - 1 && nums[q] < nums[q - 1]) {
        q++;
    }

    // Check if the remaining part is strictly increasing
    while (q < n - 1 && nums[q] < nums[q + 1]) {
        q++;
    }

    // Check if the entire array is divided into three parts as required
    return p >= 2 && q <= n - 2 && nums[p] > nums[p - 1] && nums[q] < nums[q - 1] && nums[q] < nums[q + 1];
}

